export type Cell = [number, number];

const keyOf = ([x, y]: Cell): string => `${x},${y}`;

const survives = (count: number): boolean => count === 2 || count === 3;
const reproduces = (count: number): boolean => count === 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(keyOf));
  const counts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = keyOf(neighbor);
        const entry = counts.get(k);
        if (entry) entry.count++;
        else counts.set(k, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, { cell, count }] of counts) {
    const isLive = live.has(k);
    if ((isLive && survives(count)) || (!isLive && reproduces(count))) {
      result.push(cell);
    }
  }
  return result;
}
